    public SourceBuilder recreateSourceBuilder(SourceBuilder eb, File file, String fileType) {
        SourceBuilder eb_new = null;
        if(fileType.toLowerCase().equals("xlsx") || fileType.toLowerCase().equals("xls") || fileType.toLowerCase().equals("xlsm")) {
            eb_new = new ExcelBuilder(eb.getApname());
            eb_new.setFileType(SourceBuilder.EXCEL);
        } else {
            eb_new = new CSVBuilder(eb.getApname());
            eb_new.setFileType(SourceBuilder.CSV);
        }
        eb_new.setRealName(file.getName().split("\\.")[0]);
        eb_new.setFileNameExtension(fileType.toLowerCase());
        eb_new.setFromListing(eb.isFromListing());
        eb_new.setPath(eb.getPath());
        eb_new.setSheet(eb.getSheet());
        eb_new.setSheetName(eb.getSheetName());
        eb_new.setSheetRight(eb.getSheetRight());
        eb_new.setCurrentStep(eb.getCurrentStep());
        eb_new.setInitStep(eb.getInitStep());
        eb_new.readFile(file, null);
        eb_new.setSync(eb.isSync());
        eb_new.setSyncUrl(eb.getSyncUrl());

        eb_new.setInitedByImportConfig(eb.isInitedByImportConfig());
        eb_new.setImportConfigKey(eb.getImportConfigKey());
        eb_new.setImportConfigName(eb.getImportConfigName());
        eb_new.setImportConfigDesc(eb.getImportConfigDesc());
        return eb_new;
    }

